package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringReader;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    @Test
    void testParse_withValidStringAndFormat_returnsCSVParser() throws IOException {
        String input = "a,b,c\n1,2,3";
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            // Assertions.notNull should be called twice with non-null arguments
            mockedAssertions.when(() -> Assertions.notNull(input, "string")).thenCallRealMethod();
            mockedAssertions.when(() -> Assertions.notNull(format, "format")).thenCallRealMethod();

            CSVParser parser = CSVParser.parse(input, format);

            assertNotNull(parser);
            assertEquals(format, parser.format);
            assertFalse(parser.isClosed());
        }
    }

    @Test
    void testParse_withNullString_throwsNullPointerException() {
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(null, "string"))
                    .thenThrow(new NullPointerException("string"));

            NullPointerException thrown = assertThrows(NullPointerException.class,
                    () -> CSVParser.parse(null, format));
            assertEquals("string", thrown.getMessage());
        }
    }

    @Test
    void testParse_withNullFormat_throwsNullPointerException() {
        String input = "a,b,c";

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(input, "string")).thenCallRealMethod();
            mockedAssertions.when(() -> Assertions.notNull(null, "format"))
                    .thenThrow(new NullPointerException("format"));

            NullPointerException thrown = assertThrows(NullPointerException.class,
                    () -> CSVParser.parse(input, null));
            assertEquals("format", thrown.getMessage());
        }
    }

    @Test
    void testParse_internalConstructorCalled() throws Exception {
        String input = "x,y,z";
        CSVFormat format = mock(CSVFormat.class);

        CSVParser parser = CSVParser.parse(input, format);

        // Using reflection to verify private fields set correctly
        var formatField = CSVParser.class.getDeclaredField("format");
        formatField.setAccessible(true);
        assertSame(format, formatField.get(parser));

        var recordNumberField = CSVParser.class.getDeclaredField("recordNumber");
        recordNumberField.setAccessible(true);
        assertEquals(0L, recordNumberField.getLong(parser));
    }
}
